  ('Sarah Nolet', 'Co-Founder & General Partner', 'Co-Founder and Managing Partner — Tenacious Ventures Group · Sarah Nolet is an internationally recognized food systems innovation expert and co-founder of Tenacious Ventures, a high-support, high conviction, sector-specific agrifood tech venture firm. Sarah has been instrumental in building the early stage agtech ecosystem - from advising dozens of startups, designing accelerator programs and consulting to established agribusinesses, to helping industry, universities and government develop and implement forward-looking initiatives in food system innovatio', 'Australia', 'Senior operator with extensive ANZ market experience.', ARRAY['International Founder', 'Fundraising / Investment'], 'https://linkedin.com/in/svnolet', NULL, NULL, 'Tenacious Ventures', FALSE, '[{"name": "Tenacious Ventures"}, {"name": "AgTech...So What? Podcast"}]'::jsonb, 'usa', ARRAY['usa', 'australia'], NULL, 'sarah-nolet', 'International Founder', ARRAY['local_startup'], TRUE, FALSE),
  ('Ram Gorlamandala', 'Founder & CEO', 'Founder & CEO @ Tat Capital | Non Executive Director I Family Offices I Venture Capital & Private Equity I Australia and India -Market access I Investment Banking I Angel Investor · As the Founder &amp; CEO of Tat Capital, I bring over 12 years of experience in cross-border advisory and investment, specializing in capital raising, M&amp;A, and market entry strategies between Australia, New Zealand, and the Indian subcontinent. Tat Capital’s ecosystem of family offices, institutional investors, and venture funds supports transformative growth opportunities and fosters strategic global partnerships. Currently serving as a Non Executive Director at 20Cube Logistics, I offer gu', 'Greater Sydney Area', '12+ years operating experience in ANZ and international markets.', ARRAY['Scaled Founder', 'Fundraising / Investment', 'Cross-border'], 'https://linkedin.com/in/ramnaresh', NULL, NULL, 'Tat Capital - Powering Growth with Purpose', FALSE, '[{"name": "Tat Capital - Powering Growth with Purpose"}, {"name": "20Cube Logistics"}]'::jsonb, NULL, ARRAY['australia'], NULL, 'ram-gorlamandala', 'Scaled Founder', ARRAY['international_entrant'], TRUE, FALSE),
